MOD = 998244353

def main():
    import sys
    input = sys.stdin.read
    data = input().split()

    N = int(data[0])
    M = int(data[1])
    S = data[2]

    # Preprocessing: for each character, store the indices in S
    from collections import defaultdict
    char_indices = defaultdict(list)
    for idx, c in enumerate(S):
        char_indices[c].append(idx)

    # DP table: dp[i][j] is the number of strings of length i with LCS at most j
    dp = [[0] * (N + 1) for _ in range(M + 1)]
    dp[0][0] = 1

    for i in range(1, M + 1):
        for j in range(N + 1):
            for c in 'abcdefghijklmnopqrstuvwxyz':
                # If the character c is not in S, it doesn't affect LCS
                if c not in char_indices:
                    dp[i][j] = (dp[i][j] + dp[i - 1][j]) % MOD
                    continue

                # Find the maximum index in S where c appears that is <= current LCS length j
                max_pos = -1
                # Iterate through positions in reverse to find the last one <= j
                for pos in reversed(char_indices[c]):
                    if pos <= j:
                        max_pos = pos
                        break

                if max_pos == -1:
                    # Character c does not contribute to LCS
                    dp[i][j] = (dp[i][j] + dp[i - 1][j]) % MOD
                else:
                    # Character contributes to LCS, new LCS is max_pos + 1
                    new_j = max_pos + 1
                    if new_j <= N:
                        dp[i][j] = (dp[i][j] + dp[i - 1][new_j]) % MOD

    # Compute answers for k from 0 to N
    ans = [0] * (N + 1)
    for k in range(N + 1):
        if k == 0:
            ans[k] = dp[M][k]
        else:
            ans[k] = (dp[M][k] - dp[M][k - 1]) % MOD

    # Ensure non-negative
    for i in range(N + 1):
        if ans[i] < 0:
            ans[i] += MOD

    print(' '.join(map(str, ans)))

if __name__ == '__main__':
    main()
